changeSet.sql:
CREATE TABLE IF NOT EXISTS agent_execution_trace ( id BIGSERIAL PRIMARY KEY, trace_id VARCHAR(64) NOT NULL UNIQUE, user_id BIGINT, session_code VARCHAR(64) NOT NULL, assistant_message_code VARCHAR(64) NOT NULL UNIQUE, client_message_id VARCHAR(64), profile_code VARCHAR(64) NOT NULL, chat_model_code VARCHAR(64) NOT NULL, request_query_masked TEXT NOT NULL, status VARCHAR(16) NOT NULL, started_at TIMESTAMPTZ NOT NULL, ended_at TIMESTAMPTZ, duration_ms BIGINT, root_span_id VARCHAR(64) NOT NULL, attempt_count INTEGER NOT NULL DEFAULT 1, error_code VARCHAR(128), error_message TEXT, summary_json TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_agent_execution_trace_session_started ON agent_execution_trace(session_code, started_at DESC); CREATE INDEX IF NOT EXISTS idx_agent_execution_trace_status_started ON agent_execution_trace(status, started_at DESC); CREATE INDEX IF NOT EXISTS idx_agent_execution_trace_user_started ON agent_execution_trace(user_id, started_at DESC);
CREATE TABLE IF NOT EXISTS agent_execution_span ( id BIGSERIAL PRIMARY KEY, trace_id VARCHAR(64) NOT NULL REFERENCES agent_execution_trace(trace_id) ON DELETE CASCADE, span_id VARCHAR(64) NOT NULL UNIQUE, parent_span_id VARCHAR(64), span_name VARCHAR(128) NOT NULL, span_type VARCHAR(16) NOT NULL, status VARCHAR(16) NOT NULL, sequence_no INTEGER NOT NULL, attempt_no INTEGER NOT NULL DEFAULT 1, started_at TIMESTAMPTZ NOT NULL, ended_at TIMESTAMPTZ, duration_ms BIGINT, input_json TEXT, output_json TEXT, tags_json TEXT, error_json TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_agent_execution_span_trace_seq ON agent_execution_span(trace_id, sequence_no, id); CREATE INDEX IF NOT EXISTS idx_agent_execution_span_parent ON agent_execution_span(parent_span_id);
CREATE TABLE IF NOT EXISTS agent_execution_event ( id BIGSERIAL PRIMARY KEY, trace_id VARCHAR(64) NOT NULL REFERENCES agent_execution_trace(trace_id) ON DELETE CASCADE, span_id VARCHAR(64) NOT NULL REFERENCES agent_execution_span(span_id) ON DELETE CASCADE, event_type VARCHAR(64) NOT NULL, sequence_no INTEGER NOT NULL, occurred_at TIMESTAMPTZ NOT NULL, payload_json TEXT NOT NULL, created_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP, updated_at TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP );
CREATE INDEX IF NOT EXISTS idx_agent_execution_event_trace_seq ON agent_execution_event(trace_id, sequence_no, id); CREATE INDEX IF NOT EXISTS idx_agent_execution_event_span_seq ON agent_execution_event(span_id, sequence_no, id);
